.darma-loader-darma-research-nebula-ribbon-orbit { --size: var(--loader-size, 96px); --speed: var(--loader-speed, 1.1s); --accent: var(--loader-color, #8b5cf6); --accent-2: var(--loader-secondary-color, #22d3ee); width: var(--size); height: var(--size); position: relative; display: grid; place-items: center; isolation: isolate; }
.darma-loader-darma-research-nebula-ribbon-orbit__core { width: 38%; height: 38%; border-radius: 50%; background: radial-gradient(circle at 35% 25%, #ffffff 0 7%, var(--accent) 18%, var(--accent-2) 58%, #070816 100%); box-shadow: 0 0 calc(var(--size) * .25) color-mix(in srgb, var(--accent) 70%, transparent), inset 0 0 calc(var(--size) * .12) #fff8; animation: darma-loader-darma-research-nebula-ribbon-orbit-nebula-core calc(var(--speed) * 2.2) ease-in-out infinite; }
.darma-loader-darma-research-nebula-ribbon-orbit__ribbon { position: absolute; width: 84%; height: 34%; border-radius: 999px; border: calc(var(--size) * .035) solid transparent; border-top-color: var(--accent); border-bottom-color: color-mix(in srgb, var(--accent-2) 80%, transparent); filter: drop-shadow(0 0 10px var(--accent)); transform: rotateX(66deg); animation: darma-loader-darma-research-nebula-ribbon-orbit-nebula-spin calc(var(--speed) * 1.7) linear infinite; }
.darma-loader-darma-research-nebula-ribbon-orbit__ribbon-b { width: 76%; height: 48%; transform: rotateX(66deg) rotateZ(70deg); animation-duration: calc(var(--speed) * 2.3); animation-direction: reverse; opacity: .75; }
.darma-loader-darma-research-nebula-ribbon-orbit__spark { position: absolute; width: 9%; height: 9%; border-radius: 50%; background: #fff; box-shadow: 0 0 14px 3px var(--accent-2); transform-origin: 0 calc(var(--size) * .34); animation: darma-loader-darma-research-nebula-ribbon-orbit-nebula-spark calc(var(--speed) * 1.7) linear infinite; }
.darma-loader-darma-research-nebula-ribbon-orbit__spark-a { top: 17%; left: 50%; }
.darma-loader-darma-research-nebula-ribbon-orbit__spark-b { top: 49%; left: 82%; animation-delay: calc(var(--speed) * -.85); }
@keyframes darma-loader-darma-research-nebula-ribbon-orbit-nebula-spin { to { rotate: 360deg; } }
@keyframes darma-loader-darma-research-nebula-ribbon-orbit-nebula-spark { to { transform: rotate(360deg); } }
@keyframes darma-loader-darma-research-nebula-ribbon-orbit-nebula-core { 0%,100% { transform: scale(.88); } 50% { transform: scale(1.08); } }

